1	package claude
2	
3	import (
4		"context"
5		"strings"
6		"time"
7	
8		"golang.org/x/sync/singleflight"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11	)
12	
13	// claudeQuotaFreshness is the constant freshness window for claude quota
14	// evidence. Mirrors DefaultClaudeQuotaStaleAfter (kept as a separate name
15	// so the CONTRACT-004 method has a stable, contract-named constant).
16	const claudeQuotaFreshness = DefaultClaudeQuotaStaleAfter
17	
18	// claudeAccountFreshness is the constant freshness window for claude
19	// account evidence. Claude embeds account info in its quota probe so the
20	// account refresh cadence matches quota.
21	const claudeAccountFreshness = DefaultClaudeQuotaStaleAfter
22	
23	// supportedLimitIDs is the stable public set of Windows[].LimitID values
24	// claude's quota probe emits. Mirrored in doc.go for human readers.
25	var supportedLimitIDs = []string{
26		"session",
27		"weekly-all",
28		"weekly-sonnet",
29		"extra",
30	}
31	
32	// supportedAliases is the stable public set of family aliases
33	// ResolveModelAlias recognizes. Mirrored in doc.go for human readers.
34	var supportedAliases = []string{"sonnet", "opus", "haiku"}
35	
36	// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
37	// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
38	// stateless wrappers — sharing the singleflight group at package scope
39	// keeps single-flight semantics correct when callers construct fresh
40	// runner instances per call (which the dispatcher does today).
41	var refreshGroup singleflight.Group
42	
43	// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
44	// snapshot owned by this harness and projects it onto QuotaStatus. A
45	// missing or undecodable cache is reported as State=QuotaUnavailable on
46	// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
47	// reserved for call failure."
48	func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
49		if err := ctx.Err(); err != nil {
50			return harnesses.QuotaStatus{}, err
51		}
52		snap, ok := ReadClaudeQuota()
53		if !ok || snap == nil {
54			return harnesses.QuotaStatus{
55				Source:            "cache",
56				State:             harnesses.QuotaUnavailable,
57				RoutingPreference: harnesses.RoutingPreferenceUnknown,
58				Reason:            "no cached snapshot",
59			}, nil
60		}
61		return claudeQuotaStatusFromSnapshot(snap, now), nil
62	}
63	
64	// RefreshQuota implements harnesses.QuotaHarness. It probes the claude
65	// CLI via PTY unconditionally and persists the result through the
66	// harness's owned cache. Single-flight per harness: concurrent callers
67	// share one cohort and observe the just-written cached state. Probe
68	// failure (binary missing, PTY error, parse failure) is reported as
69	// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
70	func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
71		if err := ctx.Err(); err != nil {
72			return harnesses.QuotaStatus{}, err
73		}
74		v, err, _ := refreshGroup.Do("claude:refresh-quota", func() (any, error) {
75			return r.refreshQuotaLocked(ctx), nil
76		})
77		if err != nil {
78			return harnesses.QuotaStatus{}, err
79		}
80		return v.(harnesses.QuotaStatus), nil
81	}
82	
83	// refreshQuotaLocked is the single-flight critical section. It probes
84	// PTY, writes the cache on success, and returns the projected status.
85	// Probe failure is folded into State=QuotaUnavailable.
86	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
87		now := time.Now()
88		timeout := claudeQuotaFreshness
89		if deadline, ok := ctx.Deadline(); ok {
90			remaining := time.Until(deadline)
91			if remaining > 0 && remaining < timeout {
92				timeout = remaining
93			}
94		}
95		var opts []QuotaPTYOption
96		if r.Binary != "" {
97			opts = append(opts, WithQuotaPTYCommand(r.Binary))
98		}
99		windows, account, _, err := captureClaudeQuotaViaPTY(ctx, timeout, opts...)
100		if err != nil {
101			state := harnesses.QuotaUnavailable
102			reason := err.Error()
103			if strings.Contains(strings.ToLower(reason), "not found in path") {
104				state = harnesses.QuotaUnauthenticated
105			}
106			return harnesses.QuotaStatus{
107				Source:            "pty",
108				CapturedAt:        now.UTC(),
109				State:             state,
110				RoutingPreference: harnesses.RoutingPreferenceUnknown,
111				Reason:            reason,
112			}
113		}
114		snap := claudeQuotaSnapshotFromWindows(windows, account)
115		if path, pathErr := ClaudeQuotaCachePath(); pathErr == nil {
116			_ = WriteClaudeQuota(path, snap)
117		}
118		return claudeQuotaStatusFromSnapshot(&snap, now)
119	}
120	
121	// QuotaFreshness implements harnesses.QuotaHarness.
122	func (r *Runner) QuotaFreshness() time.Duration {
123		return claudeQuotaFreshness
124	}
125	
126	// SupportedLimitIDs implements harnesses.QuotaHarness.
127	func (r *Runner) SupportedLimitIDs() []string {
128		return append([]string(nil), supportedLimitIDs...)
129	}
130	
131	// AccountStatus implements harnesses.AccountHarness. Claude embeds
132	// account/plan info inside its quota probe, so this method projects the
133	// quota cache's Account field onto AccountSnapshot.
134	func (r *Runner) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
135		if err := ctx.Err(); err != nil {
136			return harnesses.AccountSnapshot{}, err
137		}
138		snap, ok := ReadClaudeQuota()
139		if !ok || snap == nil {
140			return harnesses.AccountSnapshot{Source: "cache"}, nil
141		}
142		return claudeAccountSnapshotFromQuotaSnapshot(snap, now), nil
143	}
144	
145	// RefreshAccount implements harnesses.AccountHarness by driving the
146	// quota probe (which carries account evidence) and projecting the
147	// resulting cached snapshot onto AccountSnapshot.
148	func (r *Runner) RefreshAccount(ctx context.Context) (harnesses.AccountSnapshot, error) {
149		if _, err := r.RefreshQuota(ctx); err != nil {
150			return harnesses.AccountSnapshot{}, err
151		}
152		return r.AccountStatus(ctx, time.Now())
153	}
154	
155	// AccountFreshness implements harnesses.AccountHarness.
156	func (r *Runner) AccountFreshness() time.Duration {
157		return claudeAccountFreshness
158	}
159	
160	// DefaultModelSnapshot implements harnesses.ModelDiscoveryHarness.
161	func (r *Runner) DefaultModelSnapshot() harnesses.ModelDiscoverySnapshot {
162		return DefaultClaudeModelDiscovery()
163	}
164	
165	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
166	// harnesses.ErrAliasNotResolvable when the supplied family is not a
167	// recognized claude alias or when the supplied discovery snapshot has
168	// no concrete model matching the family.
169	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
170		normalized := strings.ToLower(strings.TrimSpace(family))
171		if !isSupportedClaudeAlias(normalized) {
172			return "", harnesses.ErrAliasNotResolvable
173		}
174		resolved := ResolveClaudeFamilyAlias(normalized, snapshot)
175		if resolved == "" {
176			return "", harnesses.ErrAliasNotResolvable
177		}
178		return resolved, nil
179	}
180	
181	// SupportedAliases implements harnesses.ModelDiscoveryHarness.
182	func (r *Runner) SupportedAliases() []string {
183		return append([]string(nil), supportedAliases...)
184	}
185	
186	func isSupportedClaudeAlias(family string) bool {
187		for _, a := range supportedAliases {
188			if a == family {
189				return true
190			}
191		}
192		return false
193	}
194	
195	// claudeQuotaStatusFromSnapshot projects the per-harness snapshot onto
196	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
197	// existing DecideClaudeQuotaRouting helper so today's "PreferClaude +
198	// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
199	// enum.
200	func claudeQuotaStatusFromSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
201		decision := DecideClaudeQuotaRouting(snap, now, claudeQuotaFreshness)
202		pref, state := mapClaudeRoutingPreference(decision)
203		status := harnesses.QuotaStatus{
204			Source:            snap.Source,
205			CapturedAt:        snap.CapturedAt,
206			Fresh:             decision.Fresh,
207			Age:               decision.Age,
208			State:             state,
209			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
210			RoutingPreference: pref,
211			Reason:            decision.Reason,
212		}
213		if snap.Account != nil {
214			acct := claudeAccountSnapshotFromQuotaSnapshot(snap, now)
215			status.Account = &acct
216		}
217		return status
218	}
219	
220	// mapClaudeRoutingPreference translates today's PreferClaude+freshness
221	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
222	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
223	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferClaude ⇒
224	// OK/Available; fresh+!PreferClaude ⇒ Blocked/Blocked.
225	func mapClaudeRoutingPreference(d ClaudeQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
226		if !d.SnapshotPresent {
227			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
228		}
229		if !d.Fresh {
230			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
231		}
232		if d.PreferClaude {
233			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
234		}
235		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
236	}
237	
238	// claudeAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
239	// the quota cache's embedded Account field. Plan-type "unknown" (written
240	// by MarkClaudeQuotaExhaustedFromMessage on runtime errors) is reported
241	// as unauthenticated evidence rather than positive authentication.
242	func claudeAccountSnapshotFromQuotaSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
243		out := harnesses.AccountSnapshot{
244			Source:     "cache",
245			CapturedAt: snap.CapturedAt,
246			Fresh:      IsClaudeQuotaFresh(snap, now, claudeAccountFreshness),
247		}
248		if snap.Account == nil {
249			return out
250		}
251		plan := strings.TrimSpace(snap.Account.PlanType)
252		out.PlanType = plan
253		out.Email = snap.Account.Email
254		out.OrgName = snap.Account.OrgName
255		switch {
256		case plan == "" || strings.EqualFold(plan, "unknown"):
257			out.Unauthenticated = true
258		default:
259			out.Authenticated = true
260		}
261		return out
262	}
263	
264	// Compile-time interface satisfaction.
265	var (
266		_ harnesses.Harness               = (*Runner)(nil)
267		_ harnesses.QuotaHarness          = (*Runner)(nil)
268		_ harnesses.AccountHarness        = (*Runner)(nil)
269		_ harnesses.ModelDiscoveryHarness = (*Runner)(nil)
270	)
