1	package gemini
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"strings"
9		"time"
10	
11		"github.com/easel/fizeau/internal/harnesses"
12		"github.com/easel/fizeau/internal/productinfo"
13		"github.com/easel/fizeau/internal/safefs"
14	)
15	
16	// GeminiQuotaSnapshot captures parsed Gemini CLI /model manage quota evidence
17	// in a durable cache so foreground routing consumers do not invoke PTY
18	// capture inline.
19	//
20	// Auth/account freshness on its own is NOT quota evidence. Only a parsed
21	// GeminiQuotaSnapshot with one or more tier windows promotes Gemini beyond
22	// the "quota unknown" state.
23	type GeminiQuotaSnapshot struct {
24		CapturedAt time.Time               `json:"captured_at"`
25		Windows    []harnesses.QuotaWindow `json:"windows"`
26		Source     string                  `json:"source"` // e.g. "pty", "cassette"
27		Account    *harnesses.AccountInfo  `json:"account,omitempty"`
28		Detail     string                  `json:"detail,omitempty"`
29	}
30	
31	const DefaultGeminiQuotaStaleAfter = 15 * time.Minute
32	
33	const geminiQuotaCacheEnv = "FIZEAU_GEMINI_QUOTA_CACHE"
34	
35	// GeminiQuotaCachePath returns the durable Gemini quota cache path.
36	func GeminiQuotaCachePath() (string, error) {
37		if path := os.Getenv(geminiQuotaCacheEnv); path != "" {
38			return path, nil
39		}
40		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
41			return filepath.Join(xdg, productinfo.ConfigDir, "gemini-quota.json"), nil
42		}
43		home, err := os.UserHomeDir()
44		if err != nil {
45			return "", err
46		}
47		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "gemini-quota.json"), nil
48	}
49	
50	// WriteGeminiQuota atomically persists a GeminiQuotaSnapshot to path.
51	func WriteGeminiQuota(path string, snapshot GeminiQuotaSnapshot) error {
52		if path == "" {
53			return fmt.Errorf("gemini quota cache path is empty")
54		}
55		if snapshot.CapturedAt.IsZero() {
56			snapshot.CapturedAt = time.Now().UTC()
57		} else {
58			snapshot.CapturedAt = snapshot.CapturedAt.UTC()
59		}
60		if snapshot.Source == "" {
61			snapshot.Source = "pty"
62		}
63		if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
64			return fmt.Errorf("create gemini quota cache dir: %w", err)
65		}
66		data, err := json.MarshalIndent(snapshot, "", "  ")
67		if err != nil {
68			return fmt.Errorf("marshal gemini quota snapshot: %w", err)
69		}
70		data = append(data, '\n')
71		tmpPath := path + ".tmp"
72		if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
73			return fmt.Errorf("write gemini quota cache tmp: %w", err)
74		}
75		if err := os.Rename(tmpPath, path); err != nil {
76			_ = os.Remove(tmpPath)
77			return fmt.Errorf("rename gemini quota cache: %w", err)
78		}
79		if err := os.Chmod(path, 0o600); err != nil {
80			return fmt.Errorf("chmod gemini quota cache: %w", err)
81		}
82		return nil
83	}
84	
85	// ReadGeminiQuotaFrom reads a Gemini quota snapshot from a specific path.
86	func ReadGeminiQuotaFrom(path string) (*GeminiQuotaSnapshot, bool) {
87		data, err := safefs.ReadFile(path)
88		if err != nil {
89			return nil, false
90		}
91		var snap GeminiQuotaSnapshot
92		if err := json.Unmarshal(data, &snap); err != nil {
93			return nil, false
94		}
95		return &snap, true
96	}
97	
98	// ReadGeminiQuota reads the default Gemini quota cache.
99	func ReadGeminiQuota() (*GeminiQuotaSnapshot, bool) {
100		path, err := GeminiQuotaCachePath()
101		if err != nil {
102			return nil, false
103		}
104		return ReadGeminiQuotaFrom(path)
105	}
106	
107	// GeminiQuotaSnapshotAge reports snapshot age relative to now.
108	func GeminiQuotaSnapshotAge(snapshot *GeminiQuotaSnapshot, now time.Time) time.Duration {
109		if snapshot == nil || snapshot.CapturedAt.IsZero() {
110			return 0
111		}
112		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
113		if age < 0 {
114			return 0
115		}
116		return age
117	}
118	
119	// IsGeminiQuotaFresh reports whether a snapshot is present and not stale.
120	func IsGeminiQuotaFresh(snapshot *GeminiQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
121		if snapshot == nil || snapshot.CapturedAt.IsZero() {
122			return false
123		}
124		if staleAfter <= 0 {
125			staleAfter = DefaultGeminiQuotaStaleAfter
126		}
127		return GeminiQuotaSnapshotAge(snapshot, now) <= staleAfter
128	}
129	
130	// GeminiQuotaRoutingDecision summarises whether foreground routing may
131	// select Gemini without probing the CLI inline. The decision is made per
132	// tier: a tier is "available" only when it has a fresh, non-exhausted
133	// quota window.
134	type GeminiQuotaRoutingDecision struct {
135		// PreferGemini is true when the snapshot is fresh and at least one
136		// non-exhausted tier is present.
137		PreferGemini bool
138		// SnapshotPresent is true when a snapshot was found (even if stale).
139		SnapshotPresent bool
140		// Fresh is true when the snapshot is present and newer than staleAfter.
141		Fresh bool
142		// Age is the snapshot age (zero when absent).
143		Age time.Duration
144		// Snapshot is the cached snapshot when present.
145		Snapshot *GeminiQuotaSnapshot
146		// AvailableTiers lists tier limit_ids (e.g. "gemini-flash") that are
147		// fresh and below the exhaustion threshold.
148		AvailableTiers []string
149		// ExhaustedTiers lists tier limit_ids currently blocked (e.g. "gemini-pro"
150		// at 100% used).
151		ExhaustedTiers []string
152		// Reason describes the diagnostic outcome.
153		Reason string
154	}
155	
156	// DecideGeminiQuotaRouting turns a durable quota snapshot into a foreground
157	// routing decision. Missing, stale, or empty quota evidence keeps Gemini out
158	// of automatic routing.
159	func DecideGeminiQuotaRouting(snapshot *GeminiQuotaSnapshot, now time.Time, staleAfter time.Duration) GeminiQuotaRoutingDecision {
160		decision := GeminiQuotaRoutingDecision{Snapshot: snapshot}
161		if snapshot == nil {
162			decision.Reason = "no cached gemini quota snapshot; assume limited"
163			return decision
164		}
165		decision.SnapshotPresent = true
166		decision.Age = GeminiQuotaSnapshotAge(snapshot, now)
167		if !IsGeminiQuotaFresh(snapshot, now, staleAfter) {
168			decision.Reason = "cached gemini quota snapshot is stale; assume limited"
169			return decision
170		}
171		decision.Fresh = true
172		if len(snapshot.Windows) == 0 {
173			decision.Reason = "fresh gemini quota snapshot has no tier windows; assume limited"
174			return decision
175		}
176		for _, w := range snapshot.Windows {
177			if isExhaustedWindow(w) {
178				decision.ExhaustedTiers = append(decision.ExhaustedTiers, w.LimitID)
179				continue
180			}
181			decision.AvailableTiers = append(decision.AvailableTiers, w.LimitID)
182		}
183		if len(decision.AvailableTiers) == 0 {
184			decision.Reason = "fresh gemini quota snapshot reports all tiers exhausted; assume limited"
185			return decision
186		}
187		decision.PreferGemini = true
188		decision.Reason = "fresh gemini quota snapshot has at least one tier with headroom"
189		return decision
190	}
191	
192	// ReadGeminiQuotaRoutingDecision reads the default cache and produces a
193	// routing decision in one call.
194	func ReadGeminiQuotaRoutingDecision(now time.Time, staleAfter time.Duration) GeminiQuotaRoutingDecision {
195		snap, _ := ReadGeminiQuota()
196		return DecideGeminiQuotaRouting(snap, now, staleAfter)
197	}
198	
199	// IsGeminiTierAvailable reports whether the tier for a concrete Gemini model
200	// is currently selectable according to the decision. An unknown model returns
201	// false so routing never silently picks a model outside the parsed tier set.
202	func (d GeminiQuotaRoutingDecision) IsGeminiTierAvailable(model string) bool {
203		if !d.PreferGemini {
204			return false
205		}
206		limitID, ok := TierLimitIDForModel(model)
207		if !ok {
208			return false
209		}
210		for _, tier := range d.AvailableTiers {
211			if tier == limitID {
212				return true
213			}
214		}
215		return false
216	}
217	
218	// MaxUsedPercent returns the largest used-percent across all tier windows in
219	// the snapshot. Returns 0 for nil/empty snapshots.
220	func (s *GeminiQuotaSnapshot) MaxUsedPercent() float64 {
221		if s == nil {
222			return 0
223		}
224		max := 0.0
225		for _, w := range s.Windows {
226			if w.UsedPercent > max {
227				max = w.UsedPercent
228			}
229		}
230		return max
231	}
232	
233	func isExhaustedWindow(w harnesses.QuotaWindow) bool {
234		if strings.EqualFold(w.State, "exhausted") || strings.EqualFold(w.State, "blocked") {
235			return true
236		}
237		return w.UsedPercent >= 95
238	}
