1	package gemini
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/easel/fizeau/internal/harnesses"
9		"github.com/easel/fizeau/internal/harnesses/ptyquota"
10		"github.com/easel/fizeau/internal/pty/cassette"
11		"github.com/easel/fizeau/internal/pty/session"
12	)
13	
14	type quotaPTYOptions struct {
15		binary      string
16		args        []string
17		workdir     string
18		env         []string
19		cassetteDir string
20	}
21	
22	// QuotaPTYOption configures a Gemini quota PTY probe.
23	type QuotaPTYOption func(*quotaPTYOptions)
24	
25	func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
26		return func(opts *quotaPTYOptions) {
27			opts.binary = binary
28			opts.args = append([]string(nil), args...)
29		}
30	}
31	
32	func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
33		return func(opts *quotaPTYOptions) {
34			opts.workdir = workdir
35		}
36	}
37	
38	func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
39		return func(opts *quotaPTYOptions) {
40			opts.env = append([]string(nil), env...)
41		}
42	}
43	
44	func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
45		return func(opts *quotaPTYOptions) {
46			opts.cassetteDir = dir
47		}
48	}
49	
50	// ReadGeminiQuotaViaPTY launches Gemini, sends /model manage, and returns the
51	// parsed tier quota windows. Callers must only treat non-empty, non-error
52	// results as authoritative — Gemini CLI renders /model manage as a version-
53	// sensitive TUI, so a timeout or empty parse means "quota unknown".
54	func ReadGeminiQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, error) {
55		windows, _, err := captureGeminiQuotaViaPTY(context.Background(), timeout, opts...)
56		return windows, err
57	}
58	
59	// RefreshGeminiQuotaViaPTY launches the probe and returns a ready-to-write
60	// durable snapshot. The Account field is filled from ReadAuthEvidence so the
61	// snapshot records auth/account context alongside quota evidence (but the
62	// quota decision is still gated on parsed windows, not on Account alone).
63	func RefreshGeminiQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (GeminiQuotaSnapshot, error) {
64		windows, _, err := captureGeminiQuotaViaPTY(context.Background(), timeout, opts...)
65		if err != nil {
66			return GeminiQuotaSnapshot{}, err
67		}
68		account := ReadAuthEvidence(time.Now()).Account
69		return GeminiQuotaSnapshot{
70			CapturedAt: time.Now().UTC(),
71			Windows:    windows,
72			Source:     "pty",
73			Account:    account,
74		}, nil
75	}
76	
77	// ReadGeminiQuotaFromCassette replays a previously recorded cassette and
78	// re-parses its final frame as Gemini /model manage output.
79	func ReadGeminiQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, error) {
80		reader, err := cassette.Open(dir)
81		if err != nil {
82			return nil, err
83		}
84		text := reader.Final().FinalText
85		if text == "" {
86			frames := reader.Frames()
87			if len(frames) > 0 {
88				text = stringsJoinLines(frames[len(frames)-1].Text)
89			}
90		}
91		windows := ParseGeminiModelManage(text)
92		if len(windows) == 0 {
93			return nil, fmt.Errorf("no gemini tier quota windows found in cassette")
94		}
95		return windows, nil
96	}
97	
98	func captureGeminiQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, ptyquota.Result, error) {
99		cfg := quotaPTYOptions{binary: "gemini"}
100		for _, opt := range opts {
101			if opt != nil {
102				opt(&cfg)
103			}
104		}
105		var windows []harnesses.QuotaWindow
106		result, err := ptyquota.Run(ctx, ptyquota.Config{
107			HarnessName:  "gemini",
108			Binary:       cfg.binary,
109			Args:         cfg.args,
110			Workdir:      cfg.workdir,
111			Env:          cfg.env,
112			Command:      "/model manage\r",
113			ReadyMarkers: []string{">", "❯"},
114			DoneWhen:     geminiQuotaComplete,
115			Timeout:      timeout,
116			Size:         session.Size{Rows: 50, Cols: 220},
117			CassetteDir:  cfg.cassetteDir,
118			Quota: func(text string) (cassette.QuotaRecord, error) {
119				windows = ParseGeminiModelManage(text)
120				if len(windows) == 0 {
121					return cassette.QuotaRecord{}, fmt.Errorf("no gemini tier quota windows found in /model manage output")
122				}
123				return geminiQuotaRecord(windows), nil
124			},
125		})
126		if err != nil {
127			return nil, result, err
128		}
129		if len(windows) == 0 {
130			windows = ParseGeminiModelManage(result.Text)
131		}
132		if len(windows) == 0 {
133			return nil, result, fmt.Errorf("no gemini tier quota windows found in /model manage output")
134		}
135		return windows, result, nil
136	}
137	
138	// geminiQuotaComplete is the probe's DoneWhen predicate. Gemini CLI renders
139	// tiers one by one as the dialog loads. Waiting for at least one tier with a
140	// parsed "% used" token is enough: tiers that never appear in the rendered
141	// dialog were not surfaced by this CLI version.
142	func geminiQuotaComplete(text string) bool {
143		windows := ParseGeminiModelManage(text)
144		return len(windows) >= 1
145	}
146	
147	func geminiQuotaRecord(windows []harnesses.QuotaWindow) cassette.QuotaRecord {
148		records := make([]map[string]any, 0, len(windows))
149		for _, window := range windows {
150			records = append(records, map[string]any{
151				"name":         window.Name,
152				"limit_id":     window.LimitID,
153				"used_percent": window.UsedPercent,
154				"resets_at":    window.ResetsAt,
155				"state":        window.State,
156			})
157		}
158		return cassette.QuotaRecord{
159			Source:            "pty",
160			Status:            string(ptyquota.StatusOK),
161			CapturedAt:        time.Now().UTC().Format(time.RFC3339),
162			FreshnessWindow:   DefaultGeminiQuotaStaleAfter.String(),
163			StalenessBehavior: "stale gemini quota evidence keeps Gemini out of automatic routing and is treated as limited",
164			Windows:           records,
165		}
166	}
167	
168	func stringsJoinLines(lines []string) string {
169		out := ""
170		for i, line := range lines {
171			if i > 0 {
172				out += "\n"
173			}
174			out += line
175		}
176		return out
177	}
