1	package gemini
2	
3	import (
4		"math"
5		"regexp"
6		"strconv"
7		"strings"
8	
9		"github.com/easel/fizeau/internal/harnesses"
10	)
11	
12	// Gemini CLI's /model manage TUI surfaces per-tier usage as rows such as:
13	//
14	//	Flash                  4% used      Resets 9:13 PM (23h 46m)
15	//	Flash Lite             0% used      Resets 9:27 PM (24h)
16	//	Pro                    100% used
17	//
18	// Names are version-sensitive; parse_gemini_model_manage accepts a small set
19	// of known tier labels and tolerates surrounding decoration (box-drawing
20	// glyphs, leading bullets, status badges).
21	
22	var geminiAnsiPattern = regexp.MustCompile(`\x1b(?:\[[0-9;?]*[a-zA-Z]|[^[])`)
23	
24	func stripGeminiANSI(s string) string {
25		return geminiAnsiPattern.ReplaceAllString(s, "")
26	}
27	
28	var (
29		geminiUsedPercentPattern = regexp.MustCompile(`(\d+(?:\.\d+)?)\s*%\s*used`)
30		geminiResetPattern       = regexp.MustCompile(`(?i)reset[s]?\s+(.*)`)
31	)
32	
33	// geminiTier represents a tier surfaced in the /model manage dialog.
34	type geminiTier struct {
35		// Label is the tier label expected in the Gemini CLI UI (case-insensitive).
36		Label string
37		// LimitID is the stable identifier persisted into cassettes and caches.
38		// Downstream consumers compare LimitIDs, not labels.
39		LimitID string
40		// DefaultModel is the concrete model ID mapped to this tier.
41		DefaultModel string
42	}
43	
44	var geminiTiers = []geminiTier{
45		{Label: "Pro", LimitID: "gemini-pro", DefaultModel: "gemini-2.5-pro"},
46		{Label: "Flash Lite", LimitID: "gemini-flash-lite", DefaultModel: "gemini-2.5-flash-lite"},
47		{Label: "Flash", LimitID: "gemini-flash", DefaultModel: "gemini-2.5-flash"},
48	}
49	
50	// ParseGeminiModelManage parses the raw text captured from `gemini` in
51	// /model manage. It returns one QuotaWindow per recognised tier, with the
52	// tier label, used percent, reset text, and a derived quota state. Tiers
53	// missing in the captured text are simply absent from the returned slice.
54	func ParseGeminiModelManage(text string) []harnesses.QuotaWindow {
55		text = stripGeminiANSI(strings.ReplaceAll(text, "\r\n", "\n"))
56		lines := strings.Split(text, "\n")
57	
58		windows := make([]harnesses.QuotaWindow, 0, len(geminiTiers))
59		seen := map[string]bool{}
60	
61		for i := 0; i < len(lines); i++ {
62			line := lines[i]
63			tier := tierForLine(line)
64			if tier == nil {
65				continue
66			}
67			if seen[tier.LimitID] {
68				continue
69			}
70			// Look at the current line and up to two following lines for the
71			// "% used" token and (optionally) a "Resets ..." fragment.
72			usedPct, hasUsed, resetText := harvestTierEvidence(lines, i)
73			if !hasUsed {
74				continue
75			}
76			seen[tier.LimitID] = true
77			windows = append(windows, harnesses.QuotaWindow{
78				Name:        tier.Label,
79				LimitID:     tier.LimitID,
80				UsedPercent: usedPct,
81				ResetsAt:    resetText,
82				State:       geminiQuotaState(usedPct),
83			})
84		}
85		return windows
86	}
87	
88	func tierForLine(line string) *geminiTier {
89		lower := strings.ToLower(line)
90		// Match longer labels first so "Flash Lite" is never matched as "Flash".
91		for i := range geminiTiers {
92			if containsTierLabel(lower, strings.ToLower(geminiTiers[i].Label)) {
93				return &geminiTiers[i]
94			}
95		}
96		return nil
97	}
98	
99	// containsTierLabel checks that the lowercase tier label appears in the line
100	// with word-like boundaries so "flashback" never matches "flash".
101	func containsTierLabel(lowerLine, lowerLabel string) bool {
102		idx := strings.Index(lowerLine, lowerLabel)
103		if idx < 0 {
104			return false
105		}
106		if idx > 0 {
107			prev := lowerLine[idx-1]
108			if isTierLabelRune(prev) {
109				return false
110			}
111		}
112		end := idx + len(lowerLabel)
113		if end < len(lowerLine) {
114			next := lowerLine[end]
115			if isTierLabelRune(next) {
116				return false
117			}
118		}
119		return true
120	}
121	
122	func isTierLabelRune(b byte) bool {
123		return (b >= 'a' && b <= 'z') || (b >= '0' && b <= '9')
124	}
125	
126	func harvestTierEvidence(lines []string, start int) (float64, bool, string) {
127		var usedPct float64
128		var hasUsed bool
129		var resetText string
130		end := start + 3
131		if end > len(lines) {
132			end = len(lines)
133		}
134		for j := start; j < end; j++ {
135			frag := lines[j]
136			if !hasUsed {
137				if m := geminiUsedPercentPattern.FindStringSubmatch(frag); m != nil {
138					if pct, err := strconv.ParseFloat(m[1], 64); err == nil {
139						usedPct = pct
140						hasUsed = true
141					}
142				}
143			}
144			if resetText == "" {
145				if m := geminiResetPattern.FindStringSubmatch(frag); m != nil {
146					resetText = strings.TrimSpace(m[1])
147				}
148			}
149			if hasUsed && resetText != "" {
150				break
151			}
152		}
153		return usedPct, hasUsed, resetText
154	}
155	
156	// geminiQuotaState mirrors harnesses.QuotaStateFromUsedPercent but treats
157	// exhausted tiers (>=100% used) as an explicit "exhausted" state so downstream
158	// routing can distinguish a fully blown tier from merely approaching the cap.
159	func geminiQuotaState(used float64) string {
160		rounded := int(math.Ceil(used))
161		if rounded >= 100 {
162			return "exhausted"
163		}
164		if rounded >= 95 {
165			return "blocked"
166		}
167		return "ok"
168	}
169	
170	// FindGeminiQuotaWindow returns the QuotaWindow matching limitID, or nil.
171	func FindGeminiQuotaWindow(windows []harnesses.QuotaWindow, limitID string) *harnesses.QuotaWindow {
172		for i := range windows {
173			if windows[i].LimitID == limitID {
174				return &windows[i]
175			}
176		}
177		return nil
178	}
179	
180	// TierLimitIDForModel returns the tier limit_id that covers the given concrete
181	// Gemini model ID (e.g. "gemini-2.5-pro" -> "gemini-pro"). Unknown models
182	// return ("", false).
183	func TierLimitIDForModel(model string) (string, bool) {
184		normalized := strings.ToLower(strings.TrimSpace(model))
185		if normalized == "" {
186			return "", false
187		}
188		// Match the more specific label first (flash-lite before flash).
189		if strings.Contains(normalized, "flash-lite") || strings.Contains(normalized, "flash lite") {
190			return "gemini-flash-lite", true
191		}
192		if strings.Contains(normalized, "pro") {
193			return "gemini-pro", true
194		}
195		if strings.Contains(normalized, "flash") {
196			return "gemini-flash", true
197		}
198		return "", false
199	}
