1	package harnesstest
2	
3	import (
4		"context"
5		"errors"
6		"sync"
7		"testing"
8		"time"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11	)
12	
13	// RunHarnessConformance asserts the contract every harnesses.Harness
14	// implementation MUST honor:
15	//
16	//   - Info returns a HarnessInfo with a non-empty Name.
17	//   - HealthCheck is callable with a non-nil context and either
18	//     returns nil or a non-nil error; the suite does not invoke any
19	//     binary and does not assert a particular outcome.
20	//   - Execute honors the setup-vs-runtime error contract documented on
21	//     the Harness interface: a non-nil error means the returned
22	//     channel is nil; a nil error means the returned channel is
23	//     non-nil. The suite drives Execute with an already-cancelled
24	//     context to keep real harnesses from launching real binaries.
25	//
26	// The suite is safe to run against in-memory synthetic harnesses and
27	// against real harnesses (e.g. &claude.Runner{}); in the latter case
28	// Execute typically returns an error because the binary path is empty
29	// or the context is cancelled before setup completes.
30	func RunHarnessConformance(t *testing.T, h harnesses.Harness) {
31		t.Helper()
32		if h == nil {
33			t.Fatal("RunHarnessConformance called with nil harness")
34		}
35	
36		t.Run("Info", func(t *testing.T) {
37			info := h.Info()
38			if info.Name == "" {
39				t.Error("Info().Name is empty")
40			}
41		})
42	
43		t.Run("HealthCheck", func(t *testing.T) {
44			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
45			defer cancel()
46			// Either nil or error is acceptable; the contract is that the
47			// call returns without panicking.
48			_ = h.HealthCheck(ctx)
49		})
50	
51		t.Run("ExecuteSetupVsRuntimeContract", func(t *testing.T) {
52			ctx, cancel := context.WithCancel(context.Background())
53			cancel()
54			ch, err := h.Execute(ctx, harnesses.ExecuteRequest{})
55			if err != nil {
56				if ch != nil {
57					t.Fatalf("Execute returned non-nil channel together with error %v", err)
58				}
59				return
60			}
61			if ch == nil {
62				t.Fatal("Execute returned nil channel with nil error")
63			}
64			// Drain whatever the harness already enqueued so we don't leak
65			// goroutines. Bound it so real harnesses cannot hang the suite.
66			drainCtx, drainCancel := context.WithTimeout(context.Background(), 2*time.Second)
67			defer drainCancel()
68			drained := false
69			for !drained {
70				select {
71				case _, ok := <-ch:
72					if !ok {
73						drained = true
74					}
75				case <-drainCtx.Done():
76					// Harness owns the channel; we don't fail the
77					// contract on a stuck producer here — the
78					// Execute-event contract has its own dedicated
79					// tests elsewhere. Stop draining.
80					drained = true
81				}
82			}
83		})
84	}
85	
86	// RunQuotaHarnessConformance asserts the QuotaHarness contract.
87	//
88	//   - The base Harness contract via RunHarnessConformance.
89	//   - QuotaStatus returns a valid value (no error) for a cold cache.
90	//   - QuotaFreshness is positive.
91	//   - SupportedLimitIDs is callable and stable (two calls return the
92	//     same multiset).
93	//   - RefreshQuota returns without error and the emitted
94	//     Windows[].LimitID is a subset of SupportedLimitIDs().
95	//   - Concurrent RefreshQuota calls all return without error and share
96	//     a consistent post-state (single-flight contract shape; exact
97	//     probe count is NOT asserted here — that belongs to harness-local
98	//     tests, e.g. the synthetic's probe counter).
99	func RunQuotaHarnessConformance(t *testing.T, h harnesses.QuotaHarness) {
100		t.Helper()
101		if h == nil {
102			t.Fatal("RunQuotaHarnessConformance called with nil harness")
103		}
104	
105		RunHarnessConformance(t, h)
106	
107		t.Run("QuotaFreshnessPositive", func(t *testing.T) {
108			if got := h.QuotaFreshness(); got <= 0 {
109				t.Errorf("QuotaFreshness() = %v, want > 0", got)
110			}
111		})
112	
113		t.Run("SupportedLimitIDsStable", func(t *testing.T) {
114			a := h.SupportedLimitIDs()
115			b := h.SupportedLimitIDs()
116			if !stringSetEqual(a, b) {
117				t.Errorf("SupportedLimitIDs not stable: first=%v second=%v", a, b)
118			}
119		})
120	
121		t.Run("QuotaStatusReturnsValue", func(t *testing.T) {
122			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
123			defer cancel()
124			if _, err := h.QuotaStatus(ctx, time.Now()); err != nil {
125				t.Errorf("QuotaStatus returned error %v; absence of evidence MUST be reported via QuotaStateValue, not error", err)
126			}
127		})
128	
129		t.Run("RefreshQuotaWindowsLimitIDSubset", func(t *testing.T) {
130			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
131			defer cancel()
132			status, err := h.RefreshQuota(ctx)
133			if err != nil {
134				// Probe failure MUST be reported as QuotaStateValue, not error.
135				t.Errorf("RefreshQuota returned error %v; probe failure MUST be reported via QuotaStateValue", err)
136				return
137			}
138			supported := stringSet(h.SupportedLimitIDs())
139			for i, w := range status.Windows {
140				if w.LimitID == "" {
141					continue
142				}
143				if _, ok := supported[w.LimitID]; !ok {
144					t.Errorf("RefreshQuota Windows[%d].LimitID = %q is not in SupportedLimitIDs() = %v", i, w.LimitID, h.SupportedLimitIDs())
145				}
146			}
147		})
148	
149		t.Run("RefreshQuotaSingleFlightShape", func(t *testing.T) {
150			const N = 8
151			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
152			defer cancel()
153	
154			var (
155				wg      sync.WaitGroup
156				mu      sync.Mutex
157				results []harnesses.QuotaStatus
158				errs    []error
159			)
160			wg.Add(N)
161			for i := 0; i < N; i++ {
162				go func() {
163					defer wg.Done()
164					s, err := h.RefreshQuota(ctx)
165					mu.Lock()
166					results = append(results, s)
167					errs = append(errs, err)
168					mu.Unlock()
169				}()
170			}
171			wg.Wait()
172	
173			for i, err := range errs {
174				if err != nil {
175					t.Errorf("concurrent RefreshQuota[%d] returned error %v; expected nil", i, err)
176				}
177			}
178			// Post-state consistency: a final QuotaStatus read MUST be a
179			// valid value (no error). The conformance suite does not
180			// pin individual field values, only the contract shape.
181			if _, err := h.QuotaStatus(ctx, time.Now()); err != nil {
182				t.Errorf("QuotaStatus after concurrent RefreshQuota returned error %v", err)
183			}
184		})
185	}
186	
187	// RunAccountHarnessConformance asserts the AccountHarness contract.
188	//
189	//   - The base Harness contract via RunHarnessConformance.
190	//   - AccountStatus returns a valid value (no error).
